import stylex from '@universe-design/stylex';
import clsx from 'clsx';
import * as React from 'react';
import { cssTypographyBody2 } from '../stylex';
import { Text } from '../text';
import { useStepsContext } from './useSteps';

const sxDescription = stylex.create({
  color: $token['icon-n3'],
});

export default (props: { stepIndex: number }) => {
  const { stepIndex } = props;
  const { steps, fixedDirection, cssScope, type, fixedLabelPlacement, showIcon, onStepClick, initial } =
    useStepsContext();

  const index = stepIndex - initial;

  const hasIcon = type !== 'navigation' || showIcon !== false;
  // eslint-disable-next-line @typescript-eslint/no-magic-numbers
  const iconSize = type === 'dot' ? 8 : hasIcon ? 28 : 0;
  const stemItemGap = index === 0 ? 0 : type === 'navigation' ? 24 : 8;
  const gapBetweenIconTitle = hasIcon ? 8 : 0;
  let margin = 0;
  if (fixedDirection === 'vertical') {
    margin = iconSize + gapBetweenIconTitle;
  } else {
    if (type === 'navigation' || fixedLabelPlacement === 'horizontal') {
      margin = iconSize + stemItemGap + gapBetweenIconTitle;
    } else {
      margin = 0;
    }
  }

  const handleClick = () => {
    onStepClick(stepIndex);
  };
  return (
    <div style={{ paddingLeft: margin }} onClick={handleClick}>
      <Text
        as="div"
        variant="body0"
        key={index}
        sx={[
          cssTypographyBody2,
          sxDescription,
          fixedLabelPlacement === 'horizontal' && stylex.create({ paddingRight: 8 }),
        ]}
        className={clsx(cssScope('__item-description'))}
        lineClamp={fixedDirection === 'horizontal' ? 2 : undefined}
      >
        {steps[index]?.description}
      </Text>
    </div>
  );
};
